# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3, HTTPProvider
import json

app = Flask(__name__)

w3 = Web3(HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

def verify_signature(message, signature, address):
    message_hash = w3.keccak(text=message)
    signed_address = w3.eth.account.recoverHash(message_hash, signature=signature)
    return signed_address.lower() == address.lower()

@app.route('/verify', methods=['POST'])
def verify():
    try:
        data = request.json
        message = data['message']
        signature = data['signature']
        address = data['address']
        if verify_signature(message, signature, address):
            return jsonify({'status': 'success', 'message': 'Signature verified and address authenticated'}), 200
        else:
            return jsonify({'status': 'failure', 'message': 'Signature verification failed'}), 400
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

if __name__ == '__main__':
    app.run(port=5000)